     if data_in_a = data_in_b then
       eq_flag <= '1';
       lt_flag <= '0';
       gt_flag <= '0';

before_code:
library ieee;
use ieee.std_logic_1164.all;

entity comparator_64bit is
  port (
    data_in_a : in std_logic_vector(63 downto 0);
    data_in_b : in std_logic_vector(63 downto 0);
    eq_flag : out std_logic;
    lt_flag : out std_logic;
    gt_flag : out std_logic
  );
end entity;

architecture rtl of comparator_64bit is
begin
  process(data_in_a)
  begin
    if data_in_a = data_in_b then
      eq_flag <= '1';
      lt_flag <= '0';
      gt_flag <= '0';
    elsif data_in_a < data_in_b then
      eq_flag <= '0';
      lt_flag <= '1';
      gt_flag <= '0';
    else
      eq_flag <= '0';
      lt_flag <= '0';
      gt_flag <= '1';
    end if;
  end process;
end architecture;

